   283→		return err
   284→	}
   285→	if err := r.gitOps.CommitChanges(ctx, repoPath, "apply(diff): transflow branch patch"); err != nil {
   286→		return fmt.Errorf("commit failed: %w", err)
   287→	}
   288→	// Build gate
   289→	timeout, err := r.config.ParseBuildTimeout()
   290→	if err != nil {
   291→		return err
   292→	}
   293→	appName := GenerateAppName(r.config.ID)
   294→	buildCfg := common.DeployConfig{
   295→		App:         appName,
   296→		Lane:        r.config.Lane,
   297→		Environment: "dev",
   298→		Timeout:     timeout,
   299→	}
   300→	res, err := r.buildChecker.CheckBuild(ctx, buildCfg)
   301→	if err != nil {
   302→		return fmt.Errorf("build gate failed: %w", err)
   303→	}
   304→	if res != nil && !res.Success {
   305→		return fmt.Errorf("build gate failed: %s", res.Message)
   306→	}
   307→	return nil
   308→}
